import mailer from "../../utils/mailer";

export default async (req, res) => {
  if (!(req.method === "POST")) {
    return res.status(501).end();
  }

  try {
    const { name, email, message } = req.body;
    // await mailer();

    res.status(200).json(true);
  } catch (err) {
    res.status(400).json(false);
  }
};
